nodes = [
    {"id": "ARCH-WEB-APP-FOUNDATION", "kind": "architecture", "depends_on": []},
    {"id": "FEAT-USER-AUTHENTICATION", "kind": "feature", "depends_on": []},
    {"id": "FEAT-PROFILE-MANAGEMENT", "kind": "feature", "depends_on": ["FEAT-USER-AUTHENTICATION"]},
]

